/**
 * Structural snapshot of the registry pillar's public surface (pillar
 * formerly named `core`). Type now lives in `manifest.generated.ts` and is
 * regenerated by `pnpm -F @pops/registry generate:manifest` (Theme 13
 * PRD-155). This file remains the stable import path
 * (`@pops/registry/manifest`) so downstream consumers don't move with the
 * generator output.
 *
 * PRD-241 US-01 adds the runtime `ModuleManifest` value for the `registry`
 * module here. PRD-241 US-02 replaced the literal in
 * `packages/module-registry/scripts/known-modules.ts` with a workspace
 * discovery walk that consumes this export.
 *
 * The registry no longer advertises the `ai.*` settings keys: the extracted
 * `ai` pillar (PRD-055) owns and advertises `ai.config`, and the registry's
 * settings surface is now its own `coreOperationalManifest` only.
 */
import { coreOperationalManifest } from './settings/index.js';

import type { ModuleManifest } from '@pops/types';

export type { CoreContract } from './manifest.generated.js';

export const coreManifest: ModuleManifest = {
  id: 'registry',
  name: 'Registry',
  version: '0.1.0',
  surfaces: ['app'],
  description: 'Cross-cutting platform services: settings, features, registry.',
  settings: [coreOperationalManifest],
};
